import React, { FC } from 'react';
import './Footer.scss';
import { Typography } from ':components/Typography';
import { classNames } from ':helpers/classnames';
import { FooterColumn, FooterNavItem, FooterProps, FooterSocialLink } from './Footer.types';

export const Footer: FC<FooterProps> = ({
	brand,
	socials = [],
	columns = [],
	copyrightText,
	privacyHref,
	privacyLabel = 'ºşº¥º╗º©ªéº©º║º░ º║º¥º¢ªäº©º┤ºÁº¢ªåº©º░º╗ªîº¢º¥ªüªéº©',
	className,
	dataTestId = 'Footer',
	...rest
}) => {
	const base = 'dsb_footer';

	const renderItem = (it: FooterNavItem) => {
		return (
			<a
				href={it.href}
				className={`${base}__link`}
				onClick={(e: React.MouseEvent) => {
					it?.onClick(e);
				}}
				{...(it.external ? { target: '_blank', rel: 'noreferrer noopener' } : {})}
			>
				<span className={classNames(`${base}__link-label`, it.disabled && `${base}__link-label-disabled`)}>
					{it.label}
				</span>
			</a>
		);
	};

	return (
		<footer className={classNames(base, className)} data-testId={dataTestId} {...rest}>
			<div className={`${base}__social`}>
				{brand && (
					<Typography inactive variant="h4" className={`${base}__brand`}>
						{brand}
					</Typography>
				)}
				{!!socials.length && (
					<div className={`${base}__social-logos`}>
						{socials.map(s => (
							<a
								href={s.href}
								target="_blank"
								rel="noreferrer noopener"
								className={`${base}__social-link`}
								aria-label={typeof s.label === 'string' ? s.label : undefined}
							>
								{s.icon}
								<span>{s.label}</span>
							</a>
						))}
					</div>
				)}
			</div>

			<div className={`${base}__copy`}>
				<div className={`${base}__copyright`}>
					{copyrightText && (
						<Typography inactive variant="body3">
							{copyrightText}
						</Typography>
					)}
					{privacyHref && (
						<a href={privacyHref} target="_blank" rel="noreferrer noopener">
							{privacyLabel}
						</a>
					)}
				</div>
			</div>

			{columns[0] && (
				<nav className={`${base}__nav ${base}__nav--1`} aria-label="Footer Navigation">
					<ul className={`${base}__list`}>
						{columns[0]?.title && (
							<li>
								<Typography inactive variant="subtitle2" className={`${base}__list-title`}>
									{columns[0]?.title}
								</Typography>
							</li>
						)}
						{columns[0]?.items?.map(it => (
							<li>{renderItem(it)}</li>
						))}
					</ul>
				</nav>
			)}

			{columns[1] && (
				<nav className={`${base}__nav ${base}__nav--2`} aria-label="Footer Navigation">
					<ul className={`${base}__list`}>
						{columns[1]?.title && (
							<li>
								<div className={`${base}__list-title`}>{columns[1]?.title}</div>
							</li>
						)}
						{columns[1]?.items?.map(it => (
							<li>{renderItem(it)}</li>
						))}
					</ul>
				</nav>
			)}
		</footer>
	);
};

export default Footer;

export type { FooterProps, FooterSocialLink, FooterNavItem, FooterColumn };
